     1|/**
     2| * Focused deploy: repaired investor-first landing index.html → S3 + CloudFront.
     3| * Mirrors the production pipeline exactly:
     4| *   1. sanitizeLandingHtml (removes duplicate runtime blocks)
     5| *   2. injectLandingCardRenderer (shared deal-card renderer)
     6| *   3. placeholder substitution with verified production values
     7| * Then uploads, invalidates CloudFront, and verifies live bytes match.
     8| *
     9| * Usage: node scripts/deploy-landing-repair.mjs   (from expo/, reads ./.env)
    10| */
    11|import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
    12|import { CloudFrontClient, ListDistributionsCommand, CreateInvalidationCommand } from '@aws-sdk/client-cloudfront';
    13|import { readFileSync } from 'fs';
    14|import { createHash } from 'crypto';
    15|import { injectLandingCardRenderer } from './landing-card-renderer-injector.mjs';
    16|import { sanitizeLandingHtml } from './landing-html-sanitizer.mjs';
    17|
    18|/* ---- load env from ./.env (line-by-line, tolerates polluted lines) ---- */
    19|const envText = readFileSync('./.env', 'utf-8');
    20|const env = {};
    21|for (const line of envText.split('\n')) {
    22|  const m = line.match(/^([A-Z0-9_]+)=(.*)$/);
    23|  if (m) env[m[1]] = m[2].trim().replace(/^["']|["']$/g, '');
    24|}
    25|const ACCESS_KEY = env.AWS_ACCESS_KEY_ID || process.env.AWS_ACCESS_KEY_ID || '';
    26|const SECRET_KEY = env.AWS_SECRET_ACCESS_KEY || process.env.AWS_SECRET_ACCESS_KEY || '';
    27|const REGION = env.AWS_REGION || 'us-east-1';
    28|if (!ACCESS_KEY || !SECRET_KEY) {
    29|  console.error('Missing AWS credentials');
    30|  process.exit(1);
    31|}
