    68|console.log('Built HTML:', html.length, 'bytes, sha256:', sha16(html));
    69|console.log('Structure: home-feed tags =', homeFeedTags, ', </html> count =', htmlCloses);
    70|if (homeFeedTags !== 1 || htmlCloses !== 1) {
    71|  console.error('Structure check failed — aborting');
    72|  process.exit(1);
    73|}
    74|
    75|/* ---- upload ---- */
    76|const BUCKET = 'ivxholding.com';
